UPDATE J09D_temp
SET ENTSCHEIDUNG = 'KSA'
WHERE HAUS IN (
    SELECT HAUS FROM (
        SELECT HAUS, COUNT(DISTINCT EQUNR) AS eq_count
        FROM J09D_temp
        GROUP BY HAUS
    )
    WHERE eq_count < 3
);

UPDATE J09D_temp
SET ENTSCHEIDUNG = 'EVU'
WHERE HAUS IN (
    SELECT HAUS FROM (
        SELECT HAUS, COUNT(DISTINCT EQUNR) AS eq_count
        FROM J09D_temp
        GROUP BY HAUS
    )
    WHERE eq_count >= 3
);
